#include "kvant/risk/simple_margin.hpp"
#include <algorithm>
#include <cmath>
#include <stdexcept>
namespace kvant::risk {MarginDecision evaluate_simple_margin(std::span<const Holding>h,money::Fixed cash,const MarginConfig&c,bool suggestions){if(c.initial_rate<0||c.maintenance_rate<0||c.maintenance_rate>c.initial_rate)throw std::invalid_argument("margin rates");long double gross=0,net=cash.decimal();for(auto&x:h){long double v=x.quantity.decimal()*x.price.decimal();gross+=std::abs(v);net+=v;}MarginDecision d;d.equity=money::Fixed::from_decimal(net,100);d.initial_required=money::Fixed::from_decimal(gross*c.initial_rate,100);d.maintenance_required=money::Fixed::from_decimal(gross*c.maintenance_rate,100);d.maintenance_breach=net<d.maintenance_required.decimal();d.block_new_risk=net<d.initial_required.decimal();if(suggestions&&d.maintenance_breach){auto copy=std::vector<Holding>(h.begin(),h.end());std::sort(copy.begin(),copy.end(),[](auto&a,auto&b){return std::abs(a.quantity.decimal()*a.price.decimal())>std::abs(b.quantity.decimal()*b.price.decimal());});long double need=d.maintenance_required.decimal()-net;for(auto&x:copy){if(need<=0)break;long double value=std::abs(x.quantity.decimal()*x.price.decimal()),reduce=std::min(value,need/std::max(c.maintenance_rate,1e-12L));d.suggested_liquidations.push_back({x.asset_id,money::Fixed::from_decimal(reduce/x.price.decimal(),money::quantity_scale)});need-=reduce*c.maintenance_rate;}}return d;}}
